const checkpoints = [];

// Read instrumentation search params
let filterParams = null;
try {
  filterParams = JSON.parse(localStorage.getItem('task1_planSearchParams') || 'null');
} catch (e) {
  filterParams = null;
}

// Read plans and signups
let plans = [];
let signups = [];
try {
  plans = JSON.parse(localStorage.getItem('plans') || '[]');
} catch (e) {
  plans = [];
}
try {
  signups = JSON.parse(localStorage.getItem('plan_signups') || '[]');
} catch (e) {
  signups = [];
}

// Checkpoint 1 (0.30): User searched with correct filters for the task
let correctFilterUsed = false;
if (filterParams) {
  const maxPriceOk = typeof filterParams.maxPrice === 'number' && filterParams.maxPrice <= 150;
  const coachingOk = filterParams.includesOneOnOneCoaching === true;
  const modulesOk = typeof filterParams.minTrainingModulesCount === 'number' && filterParams.minTrainingModulesCount >= 5;
  const starterOk = filterParams.onlyStarterPlans !== false; // true or undefined both mean starter-only in this context
  const sortOk = filterParams.sortBy === 'price_low_to_high';
  correctFilterUsed = maxPriceOk && coachingOk && modulesOk && starterOk && sortOk;
}
checkpoints.push({ passed: correctFilterUsed, weight: 0.30 });

// Identify the user's signup based on provided contact details
const targetName = 'alex rivera';
const targetEmail = 'alex@example.com';
const userSignups = signups.filter((s) => 
  s && typeof s.name === 'string' && typeof s.email === 'string' &&
  s.name.toLowerCase().trim() === targetName &&
  s.email.toLowerCase().trim() === targetEmail
);

let selectedSignup = null;
if (userSignups.length > 0) {
  selectedSignup = userSignups.reduce((latest, s) => {
    if (!latest) return s;
    if (!latest.created_at) return s;
    if (!s.created_at) return latest;
    return new Date(s.created_at).getTime() > new Date(latest.created_at).getTime() ? s : latest;
  }, null);
}

const selectedPlan = selectedSignup ? plans.find((p) => p.id === selectedSignup.plan_id) : null;

// Determine if the selected plan meets all task criteria
const selectedPlanQualifies = !!(selectedPlan &&
  selectedPlan.status === 'active' &&
  selectedPlan.is_starter_plan === true &&
  selectedPlan.includes_one_on_one_coaching === true &&
  typeof selectedPlan.training_modules_count === 'number' && selectedPlan.training_modules_count >= 5 &&
  typeof selectedPlan.price === 'number' && selectedPlan.price <= 150
);

// Checkpoint 2 (0.30): User started signup for a qualifying plan with the correct contact details
const startedSignupForQualifyingPlan = !!(selectedSignup && selectedPlanQualifies);
checkpoints.push({ passed: startedSignupForQualifyingPlan, weight: 0.30 });

// Compute the cheapest qualifying plan dynamically
const qualifyingPlans = plans.filter((p) => p &&
  p.status === 'active' &&
  p.is_starter_plan === true &&
  p.includes_one_on_one_coaching === true &&
  typeof p.training_modules_count === 'number' && p.training_modules_count >= 5 &&
  typeof p.price === 'number' && p.price <= 150
);

let cheapestPlan = null;
if (qualifyingPlans.length > 0) {
  cheapestPlan = qualifyingPlans.reduce((min, p) => {
    if (!min) return p;
    if (typeof p.price !== 'number') return min;
    if (typeof min.price !== 'number') return p;
    return p.price < min.price ? p : min;
  }, null);
}

const selectedIsCheapest = !!(selectedPlanQualifies && cheapestPlan && selectedPlan && selectedPlan.id === cheapestPlan.id);

// Checkpoint 3 (0.40): Selected plan is the cheapest among all qualifying plans
checkpoints.push({ passed: selectedIsCheapest, weight: 0.40 });

// Final score
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Read instrumentation search params
let searchParams = null;
try {
  searchParams = JSON.parse(localStorage.getItem('task2_webinarSearchParams') || 'null');
} catch (e) {
  searchParams = null;
}

// Read webinars and registrations
let webinars = [];
let regs = [];
try {
  webinars = JSON.parse(localStorage.getItem('webinars') || '[]');
} catch (e) {
  webinars = [];
}
try {
  regs = JSON.parse(localStorage.getItem('webinar_registrations') || '[]');
} catch (e) {
  regs = [];
}

const baseline = new Date('2026-03-03T00:00:00Z');
const baselineTime = baseline.getTime();
const maxEndTime = baselineTime + 14 * 24 * 60 * 60 * 1000; // next 14 days

// Helper to check weekday (Mon-Fri) using UTC day
function isWeekday(dateObj) {
  const day = dateObj.getUTCDay();
  return day >= 1 && day <= 5;
}

// Checkpoint 1 (0.30): User searched with correct webinar filters
let correctSearchUsed = false;
if (searchParams) {
  const startTime = searchParams.startDate ? new Date(searchParams.startDate).getTime() : null;
  const endTime = searchParams.endDate ? new Date(searchParams.endDate).getTime() : null;

  const dateOk = startTime != null && endTime != null &&
    startTime >= baselineTime &&
    endTime <= maxEndTime;

  const timeOfDayOk = searchParams.timeOfDay === 'evening';
  const sortOk = searchParams.sortBy === 'earliest_date_first';
  const topicTypes = Array.isArray(searchParams.topicTypes) ? searchParams.topicTypes : [];
  const topicsOk = topicTypes.includes('introductory_overview') || topicTypes.includes('getting_started_overview');

  correctSearchUsed = dateOk && timeOfDayOk && sortOk && topicsOk;
}
checkpoints.push({ passed: correctSearchUsed, weight: 0.30 });

// Identify the user's registration based on provided contact details
const targetName = 'pat morgan';
const targetEmail = 'pat@example.com';
const userRegs = regs.filter((r) => 
  r && typeof r.name === 'string' && typeof r.email === 'string' &&
  r.name.toLowerCase().trim() === targetName &&
  r.email.toLowerCase().trim() === targetEmail
);

let selectedReg = null;
if (userRegs.length > 0) {
  selectedReg = userRegs.reduce((latest, r) => {
    if (!latest) return r;
    if (!latest.registered_at) return r;
    if (!r.registered_at) return latest;
    return new Date(r.registered_at).getTime() > new Date(latest.registered_at).getTime() ? r : latest;
  }, null);
}

const selectedWebinar = selectedReg ? webinars.find((w) => w.id === selectedReg.webinar_id) : null;

// Determine if the selected webinar meets all task criteria
let webinarQualifies = false;
if (selectedWebinar) {
  const startTime = new Date(selectedWebinar.start_datetime).getTime();
  const withinRange = startTime >= baselineTime && startTime <= maxEndTime;
  const weekdayOk = isWeekday(new Date(selectedWebinar.start_datetime));
  const topicOk = selectedWebinar.topic_type === 'introductory_overview' || selectedWebinar.topic_type === 'getting_started_overview';
  webinarQualifies = selectedWebinar.status === 'scheduled' &&
    selectedWebinar.time_of_day === 'evening' &&
    topicOk &&
    withinRange &&
    weekdayOk;
}

// Registration details (time zone + reminder preference)
const registrationDetailsOk = !!(selectedReg &&
  selectedReg.selected_time_zone === 'us_eastern' &&
  selectedReg.reminder_preference === 'email_only'
);

// Checkpoint 2 (0.30): User registered for a qualifying webinar with correct registration details
const registeredForQualifyingWebinar = webinarQualifies && registrationDetailsOk;
checkpoints.push({ passed: registeredForQualifyingWebinar, weight: 0.30 });

// Determine the earliest qualifying webinar dynamically
const qualifyingWebinars = webinars.filter((w) => {
  if (!w || w.status !== 'scheduled') return false;
  const start = new Date(w.start_datetime).getTime();
  const withinRange = start >= baselineTime && start <= maxEndTime;
  const weekdayOk = isWeekday(new Date(w.start_datetime));
  const topicOk = w.topic_type === 'introductory_overview' || w.topic_type === 'getting_started_overview';
  return withinRange && weekdayOk && w.time_of_day === 'evening' && topicOk;
});

let earliestWebinar = null;
if (qualifyingWebinars.length > 0) {
  earliestWebinar = qualifyingWebinars.reduce((earliest, w) => {
    if (!earliest) return w;
    const t = new Date(w.start_datetime).getTime();
    const te = new Date(earliest.start_datetime).getTime();
    return t < te ? w : earliest;
  }, null);
}

const registeredEarliest = !!(registeredForQualifyingWebinar && earliestWebinar && selectedWebinar && selectedWebinar.id === earliestWebinar.id);

// Checkpoint 3 (0.40): Registered webinar is the earliest qualifying one
checkpoints.push({ passed: registeredEarliest, weight: 0.40 });

// Final score
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

